  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import supabase from '../../utils/supabaseClient';
  7→import useUniverseCamera from './hooks/useUniverseCamera';
  8→import useCosmicGravity from './hooks/useCosmicGravity';
  9→
 10→import DeepSpaceLayer from './layers/DeepSpaceLayer';
 11→import MidGalaxyLayer from './layers/MidGalaxyLayer';
 12→import NebulaLayer from './layers/NebulaLayer';
 13→import InteractiveLayer from './layers/InteractiveLayer';
 14→import WormholeLayer from './layers/WormholeLayer';
 15→import UniverseMinimap from './components/UniverseMinimap';
 16→import { extractSnippet, MIN_UNIVERSE_ZOOM, userHomeCoords } from './utils/starUtils';
 17→import {
 18→    buildSectorIndex,
 19→    computeGalaxyCentroids,
 20→    computeSectorKey,
 21→    getNeighborSectorKeys,
 22→} from './utils/cosmicPhysics';
 23→import { handleClickProfile } from '../../../helpers/handleClicks';
 24→import styles from './Universe.module.css';
 25→
 26→const SECTOR_SIZE = 2000;
 27→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 28→
 29→const Universe = () => {
 30→    const navigate = useNavigate();
 31→    const { user } = useAuth();
 32→    const userId = user?.userData?.[0]?.id || null;
 33→
 34→    const fetchDebounceRef = useRef(null);
 35→    const settleDebounceRef = useRef(null);
 36→    const lastSettledPayloadRef = useRef('');
 37→    const initialFetchResolvedRef = useRef(false);
 38→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 39→    const ownGalaxyLookupStartedRef = useRef(false);
 40→
 41→    const [posts, setPosts] = useState(new Map());
 42→    const [selectedPost, setSelectedPost] = useState(null);
 43→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 44→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 45→    const [pulsingId, setPulsingId] = useState(null);
 46→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 47→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 48→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 49→    const [wormholes, setWormholes] = useState([]);
 50→    const [isWarping, setIsWarping] = useState(false);
 51→
 52→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 53→    const [centroids, setCentroids] = useState([]);
 54→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 55→    const [similarPairs, setSimilarPairs] = useState([]);
 56→    const [starPulls, setStarPulls] = useState([]);
 57→
 58→    // Shared ref: prevents camera pan while dragging a star
 59→    const isStarDragging = useRef(false);
 60→
 61→    const {
 62→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 63→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 64→    } = useUniverseCamera(userId, hasOwnPosts, isStarDragging);
 65→
 66→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 67→    const showTitles = zoom > 0.5;
 68→
 69→    // Sector partitioning for scalable local gravity math.
 70→    const postSectorIndex = useMemo(() => (
 71→        buildSectorIndex(
 72→            postArray,
 73→            (post) => ({
 74→                x: post?.display_x ?? post?.universe_x,
 75→                y: post?.display_y ?? post?.universe_y,
 76→            }),
 77→            SECTOR_SIZE
 78→        )
 79→    ), [postArray]);
 80→
 81→    const centerSectorKey = useMemo(
 82→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 83→        [centerWorld.x, centerWorld.y]
 84→    );
 85→
 86→    const activeSectorKeys = useMemo(
 87→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
 88→        [centerSectorKey]
 89→    );
 90→
 91→    const activePosts = useMemo(() => {
 92→        if (activeSectorKeys.size === 0) return postArray;
 93→
 94→        const next = [];
 95→        for (const key of activeSectorKeys) {
 96→            const bucket = postSectorIndex.get(key);
 97→            if (bucket?.length) next.push(...bucket);
 98→        }
 99→        return next;
100→    }, [postArray, postSectorIndex, activeSectorKeys]);
101→
102→    const activePostIds = useMemo(() => {
103→        const ids = new Set();
104→        for (const post of activePosts) {
105→            if (post?.id) ids.add(post.id);
106→        }
107→        return ids;
108→    }, [activePosts]);
109→
110→    const { centroidByUser } = useMemo(
111→        () => computeGalaxyCentroids(postArray),
112→        [postArray]
113→    );
114→
115→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
116→    const hashGalaxies = useMemo(() => {
117→        const seen = new Map();
118→        for (const post of postArray) {
119→            const uid = post.users?.id ?? post.user_id;
120→            if (!uid || seen.has(uid)) continue;
121→            const hash = userHomeCoords(uid);
122→            seen.set(uid, {
123→                userId: uid,
124→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
125→                x: hash.x,
126→                y: hash.y,
127→            });
128→        }
129→        return Array.from(seen.values());
130→    }, [postArray]);
131→
132→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
133→    const centroidTargets = useMemo(() => {
134→        const map = new Map();
135→        for (const c of centroids) {
136→            if (c.galaxy_x != null && c.galaxy_y != null) {
137→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
138→            }
139→        }
140→        return map;
141→    }, [centroids]);
142→
143→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
144→    const {
145→        galaxyPositions,
146→        starPullOffsets,
147→        isSettled,
148→        galaxyEdges: effectiveGalaxyEdges,
149→        hasEmbeddingGravity,
150→    } = useCosmicGravity({
151→        galaxies: hashGalaxies,
152→        centroidTargets,
153→        edges: galaxyEdges,
154→        posts: postArray,
155→        starPulls,
156→        centroidByUser,
157→        activeSectorKeys,
158→        activePostIds,
159→        sectorSize: SECTOR_SIZE,
160→    });
161→
162→    // ── Render galaxies = hash galaxies with animated positions ──────
163→    const galaxies = useMemo(() => {
164→        return hashGalaxies.map(g => {
165→            const animated = galaxyPositions.get(g.userId);
166→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
167→        });
168→    }, [hashGalaxies, galaxyPositions]);
169→
170→    // Home position for distance tracker — same resolution as auto-focus.
171→    const homePosition = useMemo(() => {
172→        if (!userId) return { x: 0, y: 0 };
173→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
174→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
175→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
176→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
177→
178→    const getComputedStarPosition = useCallback((post) => {
179→        if (!post) return null;
180→
181→        const uid = post.users?.id ?? post.user_id;
182→        const hashGal = userHomeCoords(uid);
183→        const animGal = galaxyPositions.get(uid);
184→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
185→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
186→        const pull = starPullOffsets.get(post.id);
187→
188→        const baseX = post.universe_x ?? post.display_x;
189→        const baseY = post.universe_y ?? post.display_y;
190→        if (baseX == null || baseY == null) return null;
191→
192→        return {
193→            x: baseX + galDx + (pull?.dx ?? 0),
194→            y: baseY + galDy + (pull?.dy ?? 0),
195→        };
196→    }, [galaxyPositions, starPullOffsets]);
197→
198→    // Resolve logged-in user's galaxy target independently from viewport data.
199→    useEffect(() => {
200→        if (!userId) return;
201→        if (ownGalaxyLookupStartedRef.current) return;
202→
203→        ownGalaxyLookupStartedRef.current = true;
204→        let cancelled = false;
205→
206→        const resolveOwnGalaxyTarget = async () => {
207→            try {
208→                const { data, error } = await supabase
209→                    .from('galaxy_centroids')
210→                    .select('galaxy_x, galaxy_y')
211→                    .eq('user_id', userId)
212→                    .maybeSingle();
213→
214→                if (cancelled) return;
215→
216→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
217→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
218→                    setHasOwnPosts(true);
219→                    return;
220→                }
221→            } catch (err) {
222→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
223→            }
224→
225→            if (!cancelled) {
226→                setOwnGalaxyTarget(userHomeCoords(userId));
227→            }
228→        };
229→
230→        resolveOwnGalaxyTarget();
231→
232→        return () => {
233→            cancelled = true;
234→        };
235→    }, [userId]);
236→
237→    // One-time wormhole fetch on mount
238→    useEffect(() => {
239→        let cancelled = false;
240→
241→        const fetchWormholes = async () => {
242→            try {
243→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
244→                    similarity_threshold: 0.7,
245→                    min_distance: 0,
246→                    max_pairs: 30,
247→                });
248→                if (cancelled) return;
249→                if (error) {
250→                    console.warn('[universe] wormhole fetch error:', error.message);
251→                    return;
252→                }
253→                console.log('[universe] wormhole pairs:', data);
254→                if (Array.isArray(data) && data.length > 0) {
255→                    setWormholes(data);
256→                }
257→            } catch (err) {
258→                if (!cancelled) {
259→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
260→                }
261→            }
262→        };
263→
264→        fetchWormholes();
265→        return () => { cancelled = true; };
266→    }, []);
267→
268→    // Debounced fetch on camera/zoom change
269→    useEffect(() => {
270→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
271→
272→        fetchDebounceRef.current = setTimeout(async () => {
273→            const bounds = getViewportBounds();
274→            try {
275→                const result = await getUniversePosts(
276→                    bounds.minX,
277→                    bounds.maxX,
278→                    bounds.minY,
279→                    bounds.maxY,
280→                    200
281→                );
282→                if (result?.data) {
283→                    setPosts(prev => {
284→                        const next = new Map(prev);
285→                        for (const post of result.data) {
286→                            next.set(post.id, post);
287→                        }
288→                        return next;
289→                    });
290→                    if (userId && hasOwnPosts !== true) {
291→                        const ownsAny = result.data.some(p =>
292→                            (p.users?.id ?? p.user_id) === userId
293→                        );
294→                        if (ownsAny) setHasOwnPosts(true);
295→                    }
296→                }
297→                // Keep server gravity data as fallback when embeddings are absent in payload.
298→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
299→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
300→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
301→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
302→            } catch (err) {
303→                console.error('Failed to fetch universe posts:', err);
304→            } finally {
305→                if (!initialFetchResolvedRef.current) {
306→                    initialFetchResolvedRef.current = true;
307→                    setIsInitialLoading(false);
308→                }
309→            }
310→        }, 400);
311→
312→        return () => {
313→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
314→        };
315→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
316→
317→    const handleStarClick = useCallback((post) => {
318→        if (isFlying.current) return;
319→        setSelectedPost(post);
320→        setSelectedGalaxy(null);
321→        setGalaxyProfile(null);
322→
323→        const position = getComputedStarPosition(post);
324→        if (!position) return;
325→
326→        flyTo(position.x, position.y, 1.2, () => {
327→            setPulsingId(post.id);
328→            setTimeout(() => setPulsingId(null), 700);
329→        });
330→    }, [flyTo, getComputedStarPosition, isFlying]);
331→
332→    const handleGalaxyClick = useCallback(async (galaxy) => {
333→        if (isFlying.current) return;
334→        setSelectedGalaxy(galaxy);
335→        setSelectedPost(null);
336→        setGalaxyProfile(null);
337→        flyTo(galaxy.x, galaxy.y, 0.8);
338→
339→        try {
340→            const data = await getUserData(galaxy.userId);
341→            const profile = data?.userData?.[0] || null;
342→            setGalaxyProfile(profile);
343→        } catch (err) {
344→            console.error('Failed to fetch galaxy profile:', err);
345→        }
346→    }, [flyTo, isFlying]);
347→
348→    const handleReadPost = useCallback(() => {
349→        if (!selectedPost) return;
350→        navigate(`/home/post/${selectedPost.id}`);
351→    }, [selectedPost, navigate]);
352→
353→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
354→        if (mode === 'drag') {
355→            jumpTo(worldX, worldY);
356→            return;
357→        }
358→        flyTo(worldX, worldY, zoom);
359→    }, [flyTo, jumpTo, zoom]);
360→
361→    // Enrich wormhole positions with live gravity-computed post coords
362→    const enrichedWormholes = useMemo(() => {
363→        return wormholes.map(wh => {
364→            const postA = posts.get(wh.post_a);
365→            const postB = posts.get(wh.post_b);
366→            const posA = postA ? getComputedStarPosition(postA) : null;
367→            const posB = postB ? getComputedStarPosition(postB) : null;
368→            return {
369→                ...wh,
370→                a_x: posA?.x ?? wh.a_x,
371→                a_y: posA?.y ?? wh.a_y,
372→                b_x: posB?.x ?? wh.b_x,
373→                b_y: posB?.y ?? wh.b_y,
374→            };
375→        });
376→    }, [wormholes, posts, getComputedStarPosition]);
377→
378→    // Find wormhole connection for a given post (if any)
379→    const getWormholeForPost = useCallback((postId) => {
380→        if (!postId || enrichedWormholes.length === 0) return null;
381→        for (const wh of enrichedWormholes) {
382→            if (wh.post_a === postId) return { wormhole: wh, side: 'a', targetTitle: wh.b_title };
383→            if (wh.post_b === postId) return { wormhole: wh, side: 'b', targetTitle: wh.a_title };
384→        }
385→        return null;
386→    }, [enrichedWormholes]);
387→
388→    const handleWormholeTravel = useCallback(() => {
389→        if (!selectedPost || isFlying.current) return;
390→        const match = getWormholeForPost(selectedPost.id);
391→        if (!match) return;
392→        const { wormhole, side } = match;
393→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
394→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
395→        setSelectedPost(null);
396→        setIsWarping(true);
397→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
398→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
399→
400→    // One-time auto focus after first payload is loaded.
401→    useEffect(() => {
402→        if (!userId) return;
403→        if (isInitialLoading) return;
404→        if (hasAutoFocusedOwnGalaxyRef.current) return;
405→
406→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
407→        const target = ownGalaxy
408→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
409→            : (centroidTargets.get(userId) || ownGalaxyTarget);
410→
411→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
412→        if (!target) return;
413→
414→        hasAutoFocusedOwnGalaxyRef.current = true;
415→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
416→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
417→
418→    const settledPayload = useMemo(() => {
419→        if (!isSettled || activePosts.length === 0) return [];
420→
421→        const payload = [];
422→        for (const post of activePosts) {
423→            if (!post?.id) continue;
424→            const pos = getComputedStarPosition(post);
425→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
426→
427→            payload.push({
428→                post_id: post.id,
429→                settled_x: Math.round(pos.x * 100) / 100,
430→                settled_y: Math.round(pos.y * 100) / 100,
431→            });
432→        }
433→
434→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
435→        return payload;
436→    }, [activePosts, getComputedStarPosition, isSettled]);
437→
438→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
439→    useEffect(() => {
440→        if (!ENABLE_SETTLED_RPC_SAVE) return;
441→        if (!isSettled || settledPayload.length === 0) return;
442→
443→        const signature = JSON.stringify(settledPayload);
444→        if (signature === lastSettledPayloadRef.current) return;
445→
446→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
447→        settleDebounceRef.current = setTimeout(async () => {
448→            lastSettledPayloadRef.current = signature;
449→            try {
450→                const { error } = await supabase.rpc('save_universe_settled_positions', {
451→                    positions_payload: settledPayload,
452→                });
453→                if (error) {
454→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
455→                }
456→            } catch (err) {
457→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
458→            }
459→        }, 1200);
460→
461→        return () => {
462→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
463→        };
464→    }, [isSettled, settledPayload]);
465→
466→    useEffect(() => {
467→        return () => {
468→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
469→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
470→        };
471→    }, []);
472→
473→    return (
474→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
475→            <button className={styles.backButton} onClick={() => navigate('/home')}>
476→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
477→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
478→                </svg>
479→                Back
480→            </button>
481→
482→            <div className={styles.distanceTracker}>
483→                {(() => {
484→                    const dx = centerWorld.x - homePosition.x;
485→                    const dy = centerWorld.y - homePosition.y;
486→                    const dist = Math.round(Math.sqrt(dx * dx + dy * dy));
487→                    return dist < 50
488→                        ? 'Home'
489→                        : `${dist.toLocaleString()} Lightyears from Home`;
490→                })()}
491→            </div>
492→
493→            {isInitialLoading && (
494→                <div className={styles.loadingOverlay}>
495→                    <div className={styles.loadingCard}>
496→                        <div className={styles.loadingSpinner} />
497→                        <div className={styles.loadingText}>Loading universe...</div>
498→                    </div>
499→                </div>
500→            )}
501→
502→            <Stage
503→                ref={stageRef}
504→                width={stageSize.width}
505→                height={stageSize.height}
506→                {...stageEvents}
507→            >
508→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
509→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
510→                <NebulaLayer
511→                    layerProps={getLayerProps(0.85)}
512→                    galaxies={galaxies}
513→                    centroids={centroids}
514→                />
515→                {enrichedWormholes.length > 0 && (
516→                    <WormholeLayer
517→                        layerProps={getLayerProps(1.0)}
518→                        wormholes={enrichedWormholes}
519→                        zoom={zoom}
520→                    />
521→                )}
522→                <InteractiveLayer
523→                    layerProps={getLayerProps(1.0)}
524→                    posts={postArray}
525→                    galaxies={galaxies}
526→                    zoom={zoom}
527→                    showTitles={showTitles}
528→                    pulsingId={pulsingId}
529→                    onStarClick={handleStarClick}
530→                    onGalaxyClick={handleGalaxyClick}
531→                    galaxyPositions={galaxyPositions}
532→                    starPullOffsets={starPullOffsets}
533→                    similarPairs={similarPairs}
534→                    galaxyEdges={effectiveGalaxyEdges}
535→                    activePostIds={activePostIds}
536→                    useEmbeddingBridges={hasEmbeddingGravity}
537→                    camera={camera}
538→                    stageSize={stageSize}
539→                />
540→            </Stage>
541→
542→            {isWarping && <div className={styles.warpOverlay} />}
543→
544→            <UniverseMinimap
545→                galaxies={galaxies}
546→                camera={camera}
547→                zoom={zoom}
548→                stageSize={stageSize}
549→                onNavigate={handleMinimapNavigate}
550→            />
551→
552→            {selectedGalaxy && galaxyProfile && (
553→                <div className={styles.galaxyPreviewPanel}>
554→                    <button
555→                        className={styles.galaxyPreviewClose}
556→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
557→                    >
558→                        &times;
559→                    </button>
560→                    <div
561→                        className={styles.galaxyPreviewBg}
562→                        style={galaxyProfile.background || {}}
563→                    />
564→                    <div className={styles.galaxyPreviewContent}>
565→                        <img
566→                            className={styles.galaxyPreviewAvatar}
567→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
568→                            alt=""
569→                        />
570→                        <div className={styles.galaxyPreviewHeading}>
571→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
572→                        </div>
573→                        {galaxyProfile.bio && (
574→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
575→                        )}
576→                        <button
577→                            className={styles.galaxyPreviewVisitBtn}
578→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
579→                        >
580→                            Visit Profile
581→                        </button>
582→                    </div>
583→                </div>
584→            )}
585→
586→            {selectedPost && (
587→                <div className={styles.previewPanel}>
588→                    <button
589→                        className={styles.previewClose}
590→                        onClick={() => setSelectedPost(null)}
591→                    >
592→                        &times;
593→                    </button>
594→                    <div className={styles.previewAuthor}>
595→                        <img
596→                            className={styles.previewAvatar}
597→                            src={selectedPost.users?.image_url || selectedPost.user_image_url || '/assets/profile.jpg'}
598→                            alt=""
599→                        />
600→                        <span className={styles.previewAuthorName}>
601→                            {selectedPost.users?.name || selectedPost.user_name || 'Anonymous'}
602→                        </span>
603→                    </div>
604→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
605→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
606→                    <div className={styles.previewLikes}>
607→                        {(() => {
608→                            const count = selectedPost.like_count != null
609→                                ? selectedPost.like_count
610→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
611→                                    ? selectedPost.likes[0].count : 0);
612→                            return `${count} like${count !== 1 ? 's' : ''}`;
613→                        })()}
614→                    </div>
615→                    <div className={styles.previewActions}>
616→                        <button className={styles.previewReadBtn} onClick={handleReadPost}>
617→                            Read
618→                        </button>
619→                        {getWormholeForPost(selectedPost.id) && (
620→                            <div className={styles.wormholeBtnWrap}>
621→                                <button className={styles.wormholeBtn} onClick={handleWormholeTravel}>
622→                                    Wormhole to "{getWormholeForPost(selectedPost.id).targetTitle}"
623→                                </button>
624→                                <div className={styles.wormholeTooltip}>
625→                                    This post is semantically linked to a distant post. Click to warp there instantly.
626→                                </div>
627→                            </div>
628→                        )}
629→                    </div>
630→                </div>
631→            )}
632→        </div>
633→    );
634→};
635→
636→export default Universe;
